import{_ as d,o as e,c as o,ag as r}from"./chunks/framework.CvgP6Fyv.js";const p=JSON.parse('{"title":"SMTP Providers","description":"","frontmatter":{},"headers":[],"relativePath":"guide/providers.md","filePath":"guide/providers.md"}'),a={name:"guide/providers.md"};function s(i,t,n,c,l,h){return e(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="smtp-providers" tabindex="-1">SMTP Providers <a class="header-anchor" href="#smtp-providers" aria-label="Permalink to &quot;SMTP Providers&quot;">​</a></h1><p>SendGrail includes pre-configured templates for 13 popular SMTP providers plus a custom SMTP option. When you select a provider, the host, port, and encryption fields are automatically filled in. You only need to supply your credentials.</p><h2 id="provider-reference" tabindex="-1">Provider Reference <a class="header-anchor" href="#provider-reference" aria-label="Permalink to &quot;Provider Reference&quot;">​</a></h2><h3 id="gmail" tabindex="-1">Gmail <a class="header-anchor" href="#gmail" aria-label="Permalink to &quot;Gmail&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Setting</th><th>Value</th></tr></thead><tbody><tr><td>Host</td><td><code>smtp.gmail.com</code></td></tr><tr><td>Port</td><td><code>587</code></td></tr><tr><td>Encryption</td><td>TLS</td></tr><tr><td>Username</td><td>Your full Gmail address</td></tr><tr><td>Password</td><td>App Password</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Gmail requires an <strong>App Password</strong> if two-factor authentication is enabled (which it should be). Generate one at <a href="https://myaccount.google.com/apppasswords" target="_blank" rel="noreferrer">myaccount.google.com/apppasswords</a>. Your regular Google password will not work.</p></div><p>Gmail has a sending limit of 500 emails per day for personal accounts and 2,000 per day for Google Workspace accounts.</p><hr><h3 id="outlook-microsoft-365" tabindex="-1">Outlook / Microsoft 365 <a class="header-anchor" href="#outlook-microsoft-365" aria-label="Permalink to &quot;Outlook / Microsoft 365&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Setting</th><th>Value</th></tr></thead><tbody><tr><td>Host</td><td><code>smtp.office365.com</code></td></tr><tr><td>Port</td><td><code>587</code></td></tr><tr><td>Encryption</td><td>TLS</td></tr><tr><td>Username</td><td>Your full Outlook email</td></tr><tr><td>Password</td><td>Your account password</td></tr></tbody></table><p>For Microsoft 365 business accounts, ensure SMTP AUTH is enabled for the mailbox in the Microsoft 365 admin center under <strong>Active users &gt; Mail &gt; Manage email apps</strong>.</p><hr><h3 id="yahoo-mail" tabindex="-1">Yahoo Mail <a class="header-anchor" href="#yahoo-mail" aria-label="Permalink to &quot;Yahoo Mail&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Setting</th><th>Value</th></tr></thead><tbody><tr><td>Host</td><td><code>smtp.mail.yahoo.com</code></td></tr><tr><td>Port</td><td><code>587</code></td></tr><tr><td>Encryption</td><td>TLS</td></tr><tr><td>Username</td><td>Your full Yahoo email</td></tr><tr><td>Password</td><td>App Password</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Yahoo requires an <strong>App Password</strong>. Generate one from <strong>Account Info &gt; Account Security &gt; Generate app password</strong>. Standard account passwords are rejected for SMTP.</p></div><hr><h3 id="sendgrid" tabindex="-1">SendGrid <a class="header-anchor" href="#sendgrid" aria-label="Permalink to &quot;SendGrid&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Setting</th><th>Value</th></tr></thead><tbody><tr><td>Host</td><td><code>smtp.sendgrid.net</code></td></tr><tr><td>Port</td><td><code>587</code></td></tr><tr><td>Encryption</td><td>TLS</td></tr><tr><td>Username</td><td><code>apikey</code> (literal string)</td></tr><tr><td>Password</td><td>Your SendGrid API key</td></tr></tbody></table><p>The username is always the literal text <code>apikey</code> -- do not enter your email address. Generate an API key from <strong>Settings &gt; API Keys</strong> in the SendGrid dashboard. The key must have <strong>Mail Send</strong> permissions.</p><hr><h3 id="mailgun" tabindex="-1">Mailgun <a class="header-anchor" href="#mailgun" aria-label="Permalink to &quot;Mailgun&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Setting</th><th>Value</th></tr></thead><tbody><tr><td>Host</td><td><code>smtp.mailgun.org</code></td></tr><tr><td>Port</td><td><code>587</code></td></tr><tr><td>Encryption</td><td>TLS</td></tr><tr><td>Username</td><td>SMTP username from Mailgun domain settings</td></tr><tr><td>Password</td><td>SMTP password from Mailgun domain settings</td></tr></tbody></table><p>Find your SMTP credentials in the Mailgun dashboard under <strong>Sending &gt; Domain settings &gt; SMTP credentials</strong>. The username is typically in the format <code>postmaster@your-domain.com</code>. Do not use your Mailgun account password.</p><hr><h3 id="amazon-ses" tabindex="-1">Amazon SES <a class="header-anchor" href="#amazon-ses" aria-label="Permalink to &quot;Amazon SES&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Setting</th><th>Value</th></tr></thead><tbody><tr><td>Host</td><td><code>email-smtp.{region}.amazonaws.com</code></td></tr><tr><td>Port</td><td><code>587</code></td></tr><tr><td>Encryption</td><td>TLS</td></tr><tr><td>Username</td><td>SES SMTP username (from IAM credentials)</td></tr><tr><td>Password</td><td>SES SMTP password (from IAM credentials)</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Replace <code>{region}</code> with your AWS region (e.g., <code>us-east-1</code>, <code>eu-west-1</code>). The host field is editable so you can specify the correct regional endpoint.</p></div><p>SES SMTP credentials are <strong>not</strong> the same as your AWS access keys. Generate them from the <strong>Amazon SES console &gt; SMTP settings &gt; Create SMTP credentials</strong>. Make sure your sending domain and email addresses are verified in SES.</p><hr><h3 id="postmark" tabindex="-1">Postmark <a class="header-anchor" href="#postmark" aria-label="Permalink to &quot;Postmark&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Setting</th><th>Value</th></tr></thead><tbody><tr><td>Host</td><td><code>smtp.postmarkapp.com</code></td></tr><tr><td>Port</td><td><code>587</code></td></tr><tr><td>Encryption</td><td>TLS</td></tr><tr><td>Username</td><td>Your Server API Token</td></tr><tr><td>Password</td><td>Your Server API Token</td></tr></tbody></table><p>Postmark uses the same Server API Token for both the username and password fields. Find it in your Postmark server under <strong>Settings &gt; API Tokens</strong>.</p><hr><h3 id="mandrill-mailchimp-transactional" tabindex="-1">Mandrill (Mailchimp Transactional) <a class="header-anchor" href="#mandrill-mailchimp-transactional" aria-label="Permalink to &quot;Mandrill (Mailchimp Transactional)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Setting</th><th>Value</th></tr></thead><tbody><tr><td>Host</td><td><code>smtp.mandrillapp.com</code></td></tr><tr><td>Port</td><td><code>587</code></td></tr><tr><td>Encryption</td><td>TLS</td></tr><tr><td>Username</td><td>Your Mailchimp email</td></tr><tr><td>Password</td><td>Your Mandrill API key</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Mandrill is a paid add-on to Mailchimp. You must have an active Mailchimp account with the Transactional Email (Mandrill) add-on enabled. Generate an API key from the Mandrill dashboard under <strong>Settings &gt; SMTP &amp; API Info</strong>.</p></div><hr><h3 id="elastic-email" tabindex="-1">Elastic Email <a class="header-anchor" href="#elastic-email" aria-label="Permalink to &quot;Elastic Email&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Setting</th><th>Value</th></tr></thead><tbody><tr><td>Host</td><td><code>smtp.elasticemail.com</code></td></tr><tr><td>Port</td><td><code>2525</code></td></tr><tr><td>Encryption</td><td>TLS</td></tr><tr><td>Username</td><td>Your Elastic Email address</td></tr><tr><td>Password</td><td>Your SMTP password</td></tr></tbody></table><p>Generate SMTP credentials from <strong>Settings &gt; SMTP</strong> in the Elastic Email dashboard. Note the non-standard port 2525.</p><hr><h3 id="smtp2go" tabindex="-1">SMTP2GO <a class="header-anchor" href="#smtp2go" aria-label="Permalink to &quot;SMTP2GO&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Setting</th><th>Value</th></tr></thead><tbody><tr><td>Host</td><td><code>mail.smtp2go.com</code></td></tr><tr><td>Port</td><td><code>2525</code></td></tr><tr><td>Encryption</td><td>TLS</td></tr><tr><td>Username</td><td>Your SMTP2GO username</td></tr><tr><td>Password</td><td>Your SMTP2GO password</td></tr></tbody></table><p>Create SMTP credentials from the SMTP2GO dashboard under <strong>Settings &gt; SMTP Users</strong>. Port 2525 is used by default to avoid ISP blocking of standard ports.</p><hr><h3 id="mailtrap" tabindex="-1">Mailtrap <a class="header-anchor" href="#mailtrap" aria-label="Permalink to &quot;Mailtrap&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Setting</th><th>Value</th></tr></thead><tbody><tr><td>Host</td><td><code>live.smtp.mailtrap.io</code> (production) or <code>sandbox.smtp.mailtrap.io</code> (testing)</td></tr><tr><td>Port</td><td><code>587</code></td></tr><tr><td>Encryption</td><td>TLS</td></tr><tr><td>Username</td><td>Your Mailtrap SMTP username</td></tr><tr><td>Password</td><td>Your Mailtrap SMTP password</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Mailtrap offers two environments. Use <code>live.smtp.mailtrap.io</code> for production email delivery and <code>sandbox.smtp.mailtrap.io</code> for development and testing. The sandbox catches all emails without delivering them to real recipients.</p></div><hr><h3 id="zoho-mail" tabindex="-1">Zoho Mail <a class="header-anchor" href="#zoho-mail" aria-label="Permalink to &quot;Zoho Mail&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Setting</th><th>Value</th></tr></thead><tbody><tr><td>Host</td><td><code>smtp.zoho.com</code></td></tr><tr><td>Port</td><td><code>587</code></td></tr><tr><td>Encryption</td><td>TLS</td></tr><tr><td>Username</td><td>Your full Zoho email</td></tr><tr><td>Password</td><td>Your password or App Password</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>If two-factor authentication is enabled on your Zoho account, you must generate an <strong>App Password</strong> from <strong>Zoho Account &gt; Security &gt; App Passwords</strong>. Your regular password will not work with 2FA active.</p></div><hr><h3 id="brevo-formerly-sendinblue" tabindex="-1">Brevo (formerly Sendinblue) <a class="header-anchor" href="#brevo-formerly-sendinblue" aria-label="Permalink to &quot;Brevo (formerly Sendinblue)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Setting</th><th>Value</th></tr></thead><tbody><tr><td>Host</td><td><code>smtp-relay.brevo.com</code></td></tr><tr><td>Port</td><td><code>587</code></td></tr><tr><td>Encryption</td><td>TLS</td></tr><tr><td>Username</td><td>Your Brevo account email</td></tr><tr><td>Password</td><td>Your SMTP key</td></tr></tbody></table><p>Find your SMTP key in the Brevo dashboard under <strong>Settings &gt; SMTP &amp; API &gt; SMTP</strong>. This is not your account password -- it is a separate SMTP-specific key.</p><hr><h3 id="custom-smtp" tabindex="-1">Custom SMTP <a class="header-anchor" href="#custom-smtp" aria-label="Permalink to &quot;Custom SMTP&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Setting</th><th>Value</th></tr></thead><tbody><tr><td>Host</td><td>Your SMTP server hostname</td></tr><tr><td>Port</td><td>Your SMTP server port</td></tr><tr><td>Encryption</td><td>None, SSL, or TLS</td></tr><tr><td>Username</td><td>Your SMTP username</td></tr><tr><td>Password</td><td>Your SMTP password</td></tr></tbody></table><p>Use the Custom SMTP option to connect to any SMTP server not listed above. All fields are fully editable. Common port and encryption combinations:</p><table tabindex="0"><thead><tr><th>Port</th><th>Encryption</th><th>Notes</th></tr></thead><tbody><tr><td><code>25</code></td><td>None</td><td>Unencrypted, often blocked</td></tr><tr><td><code>465</code></td><td>SSL</td><td>Implicit TLS (legacy)</td></tr><tr><td><code>587</code></td><td>TLS</td><td>STARTTLS, recommended</td></tr><tr><td><code>2525</code></td><td>TLS</td><td>Alternative to avoid blocks</td></tr></tbody></table><h2 id="quick-reference" tabindex="-1">Quick Reference <a class="header-anchor" href="#quick-reference" aria-label="Permalink to &quot;Quick Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Provider</th><th>Host</th><th>Port</th><th>Encryption</th></tr></thead><tbody><tr><td>Gmail</td><td><code>smtp.gmail.com</code></td><td><code>587</code></td><td>TLS</td></tr><tr><td>Outlook / Microsoft 365</td><td><code>smtp.office365.com</code></td><td><code>587</code></td><td>TLS</td></tr><tr><td>Yahoo Mail</td><td><code>smtp.mail.yahoo.com</code></td><td><code>587</code></td><td>TLS</td></tr><tr><td>SendGrid</td><td><code>smtp.sendgrid.net</code></td><td><code>587</code></td><td>TLS</td></tr><tr><td>Mailgun</td><td><code>smtp.mailgun.org</code></td><td><code>587</code></td><td>TLS</td></tr><tr><td>Amazon SES</td><td><code>email-smtp.{region}.amazonaws.com</code></td><td><code>587</code></td><td>TLS</td></tr><tr><td>Postmark</td><td><code>smtp.postmarkapp.com</code></td><td><code>587</code></td><td>TLS</td></tr><tr><td>Mandrill</td><td><code>smtp.mandrillapp.com</code></td><td><code>587</code></td><td>TLS</td></tr><tr><td>Elastic Email</td><td><code>smtp.elasticemail.com</code></td><td><code>2525</code></td><td>TLS</td></tr><tr><td>SMTP2GO</td><td><code>mail.smtp2go.com</code></td><td><code>2525</code></td><td>TLS</td></tr><tr><td>Mailtrap (Production)</td><td><code>live.smtp.mailtrap.io</code></td><td><code>587</code></td><td>TLS</td></tr><tr><td>Mailtrap (Sandbox)</td><td><code>sandbox.smtp.mailtrap.io</code></td><td><code>587</code></td><td>TLS</td></tr><tr><td>Zoho Mail</td><td><code>smtp.zoho.com</code></td><td><code>587</code></td><td>TLS</td></tr><tr><td>Brevo</td><td><code>smtp-relay.brevo.com</code></td><td><code>587</code></td><td>TLS</td></tr></tbody></table>',63)])])}const u=d(a,[["render",s]]);export{p as __pageData,u as default};
